const { spawn } = require('child_process');
const fs = require('fs');

const backupDatabase = (dbName) => {
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const filename = `${dbName}-backup-${timestamp}.sql`;
  const writeStream = fs.createWriteStream(filename);

  const dumpProcess = spawn('pg_dump', [dbName]);

  dumpProcess.stdout.pipe(writeStream);

  dumpProcess.stderr.on('data', (data) => {
    console.error(`pg_dump stderr: ${data}`);
  });

  dumpProcess.on('error', (error) => {
    console.error(`Failed to start pg_dump: ${error.message}`);
  });

  dumpProcess.on('close', (code) => {
    if (code === 0) {
      console.log(`Backup completed successfully: ${filename}`);
    } else {
      console.error(`Backup process exited with code ${code}`);
    }
  });
};

