function encryptSensitiveData(plaintext) {
  const algorithm = 'aes-256-cbc';
  // Key must be 32 bytes for aes-256-cbc. Stored in environment variable recommended.
  const key = process.env.ENCRYPTION_KEY ? Buffer.from(process.env.ENCRYPTION_KEY, 'hex') : crypto.randomBytes(32);
